          "value": "low",
          "reason": "The process structure remains unchanged except for adding one sequential activity. No additional gateways, branches, or loops are introduced."
        },
        "change_location": {
          "value": "middle",
          "reason": "The change is applied inside the high-risk loan handling branch, which occurs after initial request handling and before contract receipt and settlement."
        }
      }
    },
    {
      "resolution_strategy_id": "RS2_insert_final_decision_with_status_write",
      "change_operations": [
